#pragma once
#include <optional>
namespace example {
class Calculator {
public:
    static int add(int a, int b);
    static std::optional<double> safe_divide(double numerator, double denominator);
    static bool is_even(int value);
};
}

implementation_code:
#include "example/calculator.hpp"
namespace example {
int Calculator::add(int a, int b) { return a + b; }
std::optional<double> Calculator::safe_divide(double numerator, double denominator) {
    if (denominator == 0.0) return std::nullopt;
    return numerator / denominator;
}
bool Calculator::is_even(int value) { return value % 2 == 0; }
}

