#pragma once
#include <optional>
#include <string>
namespace example {
class Parser {
public:
    static std::optional<int> parse_port(const std::string& text);
};
}

implementation_code:
#include "example/parser.hpp"
#include <cctype>
namespace example {
std::optional<int> Parser::parse_port(const std::string& text) {
    if (text.empty()) return std::nullopt;
    for (char c : text) { if (!std::isdigit(static_cast<unsigned char>(c))) return std::nullopt; }
    int value = std::stoi(text);
    if (value < 1 || value > 65535) return std::nullopt;
    return value;
}
}

