#pragma once
#include <string>
#include <vector>
namespace example {
class Tokenizer {
public:
    static std::vector<std::string> split_csv(const std::string& line);
};
}

implementation_code:
#include "example/tokenizer.hpp"
namespace example {
std::vector<std::string> Tokenizer::split_csv(const std::string& line) {
    std::vector<std::string> out;
    std::string current;
    for (char ch : line) {
        if (ch == ',') {
            out.push_back(current);
            current.clear();
        } else {
            current.push_back(ch);
        }
    }
    out.push_back(current);
    return out;
}
}
